function removeGreekAccentsAndToUpper(f){const j={'ά':'Α','έ':'Ε','ή':'Η','ί':'Ι','ό':'Ο','ύ':'Υ','ώ':'Ω','Ά':'Α','Έ':'Ε','Ή':'Η','Ί':'Ι','Ό':'Ο','Ύ':'Υ','Ώ':'Ω','ϊ':'Ι','ΐ':'Ι','ϋ':'Υ','ΰ':'Υ','Ϊ':'Ι','Ϋ':'Υ'};return f['split']('')['map'](function(s){return j[s]||s;})['join']('')['toUpperCase']();}